#include <bits/stdc++.h>
using namespace std;

int main(){
string s, s1, s2, s3;
s1 = "74";
s2 = "94";
s3 = "79";
for (int i = 0; i < 40; i++){
s += "4";
}
for (int i = 0; i < 40; i++){
s += "7";
}
for (int i = 0; i < 40; i++){
s += "9";
}
while (s.find("47") != std::string::npos || s.find("49") !=
std::string::npos || s.find("97") != std::string::npos){
if (s.find("47") != std::string::npos)
s = s.replace(s.find("47"), 2, s1);
else if (s.find("49") != std::string::npos)
s = s.replace(s.find("49"), 2, s2);
else if (s.find("97") != std::string::npos)
s = s.replace(s.find("97"), 2, s3);
}
cout << s[24];
cout << s[70];
cout << s[104];
}
